def detect_safety_latency(agent: LlamaStackAgent):
    turn_metrics = agent.metrics.turn_history[-5:]  # last 5 turns
    for turn in turn_metrics:
        safety_time = turn.get('safety_shield_duration', 0)
        if safety_time > 2.0:
            return {
                'severity': 'medium',
                'safety_duration': safety_time,
                'content_length': len(turn.get('raw_output', '')),
                'turn_id': turn['turn_id']
            }
    return None

from llama_stack_client import LlamaStackAgent

def detect_loop_timeouts(agent: LlamaStackAgent):
    recent_turns = agent.metrics.turn_history[-10:]
    slow_turns = []
    for turn in recent_turns:
        if turn.get('total_duration', 0) > 25.0:
            slow_turns.append({
                'turn_id': turn['turn_id'],
                'duration': turn['total_duration'],
                'breakdown': turn.get('timing_breakdown', {})
            })
    return {'slow_turns': slow_turns} if slow_turns else None

